//go:build integration

package testchain

// erc2612BytecodeHex is the creation bytecode for the minimal test EIP-2612 permit
// token (name "Permit Test", symbol "PTST", 18 decimals; constructor mints
// 1,000,000 PTST to the deployer). It implements the canonical EIP-2612 permit()
// with the standard PERMIT_TYPEHASH and an EIP-712 domain separator bound to
// (name, version "1", block.chainid, address(this)) — so a Daxie-signed EIP-2612
// Permit verifies on-chain and sets the allowance (the load-bearing roundtrip in
// sign_integration_test.go). Compiled offline with solc 0.8.26 (optimizer on, 200
// runs) from a standalone, no-import source (see the header comment in erc2612.go)
// and checked in so the integration test needs no solc at run time. Mirrors
// erc20bytecode.go.
const erc2612BytecodeHex = ""
